…
for (int i = 0; i<n; i++)
printf(“%d”, a[i]);
printf(“%d”, pa[i]);
printf(“%d”, *(a + i));
printf(“%d”, *(pa + i));
printf(“%d”, *(a++));
printf(“%d”, *(pa++));
}
➔a[i] *(a + i) *(pa + i) pa[i]

