/* Ham tinh giai thua */ 

#include <stdio.h> 
#include <conio.h> 

void main(void) 
{ 
 int in; 
 long giaithua(int); 
 printf("Nhap vao so n: "); 
 scanf("%d", &in); 
 printf("%d! = %ld.", in, giaithua(in)); 
 getch(); 
} 

long giaithua(int in) 
{ 
 int i; 
 long ltich = 1; 
 if (in == 0) 
  return (1L); 
 else 
 { 
 for (i = 1; i <= in; i++) 
   ltich *= i; 
  return (ltich); 
 } 
} 
